def test_hr_admin_updates_onboarding_task_success(client, auth_token_hr_admin):
    task_id = 'task-001'
    payload = {
        'title': 'Updated Task Title',
        'description': 'Updated description text',
        'assigned_to': 'user-123',
        'due_date': '2025-12-31'
    }
    headers = {'Authorization': f'Bearer {auth_token_hr_admin}'}
    resp = client.put(
        f'/onboarding-tasks/{task_id}',
        json=payload,
        headers=headers
    )
    assert resp.status_code in [200, 201]
    assert resp.json()['id'] == task_id
    audit_check = <helper_fn_verify_audit_record>(
        task_id, 'update', 'hr-admin'
    )
    assert audit_check is True

def test_hr_admin_update_insufficient_role_permission_denied(client, auth_token_standard_user):
    task_id = 'task-004'
    payload = {
        'title': 'Updated Title',
        'description': 'Updated description',
        'assigned_to': 'user-999',
        'due_date': '2025-12-31'
    }
    headers = {'Authorization': f'Bearer {auth_token_standard_user}'}
    resp = client.put(
        f'/onboarding-tasks/{task_id}',
        json=payload,
        headers=headers
    )
    assert resp.status_code == 403
    assert 'forbidden' in resp.json()['error'].lower()

